// protocol.ts line 144 (comment):
partialPixelStride?: number;  // bytes per row; required when partialPixels is present

// decode-handler.ts failSession():
if (partialPixels !== undefined && partialInfo !== undefined) {
  msg.partialPixels = partialPixels;
  msg.partialInfo = partialInfo;
  if (partialPixelStride !== undefined) msg.partialPixelStride = partialPixelStride; // can be absent!
  if (partialStage !== undefined) msg.partialStage = partialStage;
  transfers.push(partialPixels);
}

// encode-handler.ts constructor:
private readonly _drainMsg = {
  type: "worker_drain" as const,
  sessionId: "" as string,
  latencyMs: 0,
  queueDepth: 0,
  queuedBytes: 0,
  adaptiveHwm: CHUNK_HWM,  // constant 4, never updated
};

// maybePostDrain() — adaptiveHwm never set before postMessage:
this._drainMsg.latencyMs = Math.round(this.pushLatencyEma);
this._drainMsg.queueDepth = this.queueDepth;
this._drainMsg.queuedBytes = this.queuedBytes;
self.postMessage(this._drainMsg); // adaptiveHwm still CHUNK_HWM

function pixelStrideForFormat(format: PixelFormat): number {
  if (format === "rgb8") return 3;
  return format === "rgbaf32" ? 16 : format === "rgba16" ? 8 : 4;
}

const decoder = this.wasm.createDecoder({
  // ...
  ...(this.opts.progressiveDetail !== null
    ? { progressiveDetail: this.opts.progressiveDetail }
    : {}),
  // ...
});

// JxlModule.createDecoder signature:
createDecoder(options: {
  // ...
  progressiveDetail?: "dc" | "lastPasses" | "passes" | "dcProgressive";
  // null is not accepted — must be omitted or undefined
}): BrowserDecoder;

function routeDecodeMessage(msg: QueuedDecodeMessage): void {
  const handler = decodeSessions.get(msg.sessionId);
  if (handler !== undefined) {
    routeToDecodeHandler(handler, msg);
  } else if (pendingDecodeStarts.has(msg.sessionId)) {
    queueDecodeMessage(msg.sessionId, msg);
  }
  // else: session ended or unknown — message silently dropped
  // no error posted, no notification to caller
}

